import wandb
from scipy.special import kl_div
import numpy as np

run = wandb.init(project="prod-monitoring", tags=["env:prod"], resume="allow")

def log_prediction_batch(preds: np.ndarray, train_dist: np.ndarray, actuals=None):
    kl = float(np.sum(kl_div(train_dist + 1e-9, preds + 1e-9)))
    payload = {"drift/kl_divergence": kl, "pred/mean": preds.mean(), "pred/std": preds.std()}
    if actuals is not None:
        payload["perf/accuracy"] = float((preds.argmax(1) == actuals).mean())
    wandb.log(payload)
    if kl > 0.2:
        wandb.alert(title="Prediction Drift Detected", text=f"KL divergence spiked to {kl:.3f}")
